mapper.select:
select count(*) from workplace where wp_usage = 'Y'
and wp_type = #{searchType}
and ( upper(wp_name) like trim(upper('%' || #{searchKeyword} || '%')) or upper(wp_id) like trim(upper('%' || #{searchKeyword} || '%')) )

SELECT * FROM ( SELECT ROWNUM RN, p.* FROM ( SELECT wp.wp_id as wpId, wp.wp_name as wpName, wp.wp_type as wpTypeNo, wt.wp_type_name as wpType, wp.wp_img as wpImg,
wt.wp_type_content as wpTypeContent, glog.glog_date lastGlogDate FROM workplace wp LEFT OUTER JOIN wp_type wt ON wp.wp_type = wt.wp_type_no LEFT OUTER JOIN ( SELECT * FROM ( SELECT glog.*, ROW_NUMBER() OVER ( PARTITION BY glog.glog_wpid ORDER BY glog.glog_date desc ) AS rn FROM ghp_log glog ) WHERE rn = 1 ) glog ON wp.wp_id = glog.glog_wpid
WHERE wp_usage = 'Y'
and wp_type = #{wpDTO.searchType}
and ( upper(wp_name) like trim(upper('%' || #{wpDTO.searchKeyword} || '%')) or upper(wp_id) like trim(upper('%' || #{wpDTO.searchKeyword} || '%')) )
ORDER BY wp_type_no, wp_id ) p ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}

mapper.update:
UPDATE WORKPLACE
SET WP_IMG = #{wpImg}
WHERE WP_ID = #{wpId}

UPDATE WORKPLACE
SET WP_NAME = #{wpName}, WP_TYPE = #{wpType}
WHERE WP_ID = #{wpId}

UPDATE WORKPLACE
SET WP_USAGE = 'N'
WHERE WP_ID = #{wpId}
